mapper.update:
UPDATE conversation_members 
SET unread_count = unread_count + #{increment}
WHERE conversation_id = #{conversationId}
AND user_id != #{userId}
AND is_left = 0

UPDATE conversation_members 
SET unread_count = 0
WHERE conversation_id = #{conversationId}
AND user_id = #{userId}
AND is_left = 0

mapper.select:
SELECT COUNT(*) > 0
FROM conversation_members
WHERE conversation_id = #{conversationId}
AND user_id = #{userId}
AND is_left = 0
AND is_deleted = 0
